// TestLibraryScannerIntegration tests the end-to-end library scanning flow
func TestLibraryScannerIntegration(t *testing.T) {
	t.Run("LibraryScanningWithMissingEcosystems", func(t *testing.T) {
		tmpDir := t.TempDir()

		// Create test lockfiles for different ecosystems
		testCases := []struct {
			name      string
			filename  string
			content   []byte
			shouldErr bool // Should detection fail?
		}{
			{
				name:     "pnpm-lock-detection",
				filename: "pnpm-lock.yaml",
				content: []byte(`lockfileVersion: 5.4
specifiers:
  axios: ^0.21.0
dependencies:
  axios: 0.21.4
`),
				shouldErr: true, // Should fail because pnpm-lock.yaml not in LibraryMap
			},
			{
				name:     "dotnet-packages-lock-detection",
				filename: "packages.lock.json",
				content: []byte(`{
  "version": 1,
  "dependencies": {
    ".NETFramework,Version=v4.7.2": {
      "NUnit": {
        "type": "Direct",
        "requested": "[3.13.0, )",
        "resolved": "3.13.0"
      }
    }
  }
}
`),
				shouldErr: true, // May fail if packages.lock.json not properly mapped
			},
		}

		for _, tc := range testCases {
			t.Run(tc.name, func(t *testing.T) {
				lockFilePath := filepath.Join(tmpDir, tc.filename)
				if err := os.WriteFile(lockFilePath, tc.content, 0644); err != nil {
					t.Fatalf("Failed to create test lockfile: %v", err)
				}

				// Try to detect the library type
				detectedType := detectLibraryType(tc.filename)

				if tc.shouldErr && detectedType == "" {
					t.Logf("DETECTED BUG: Expected missing detection for %s - lockfile won't be scanned for vulnerabilities", tc.filename)
				} else if detectedType == "" {
					t.Logf("Library type not detected for %s", tc.filename)
				} else {
					t.Logf("Successfully detected library type for %s: %s", tc.filename, detectedType)
				}
			})
		}
	})
}

// TestMultipleEcosystemsCoverage tests that various lockfile types are recognized
func TestMultipleEcosystemsCoverage(t *testing.T) {
	libraryMap := getLibraryMap()

	testCases := []struct {
		filename     string
		expectedType string
		isSupported  bool
	}{
		{"package-lock.json", "node", true},
		{"yarn.lock", "node", true},
		{"pnpm-lock.yaml", "node", false}, // BUG: Not supported
		{"pnpm-lock.yml", "node", false},  // BUG: Not supported
		{"Gemfile.lock", "ruby", true},
		{"Cargo.lock", "rust", true},
		{"composer.lock", "php", true},
		{"poetry.lock", "python", true},
		{"packages.lock.json", ".net", true},
		{"go.mod", "gomod", true},
		{"pom.xml", "java", true},
	}

	var missingSupport []string
	for _, tc := range testCases {
		detectedType, exists := libraryMap[tc.filename]
		if tc.isSupported && !exists {
			missingSupport = append(missingSupport, tc.filename)
			t.Logf("BUG DETECTED: %s (expected type: %s) is not in LibraryMap", tc.filename, tc.expectedType)
		} else if tc.isSupported && detectedType != tc.expectedType {
			t.Logf("WARNING: %s detected as %s, expected %s", tc.filename, detectedType, tc.expectedType)
		} else if !tc.isSupported && !exists {
			t.Logf("KNOWN BUG: %s is not supported (expected behavior given the bug)", tc.filename)
		}
	}

	if len(missingSupport) > 0 {
		t.Logf("ECOSYSTEM SUPPORT GAP: These lockfile formats are missing: %v", missingSupport)
	}
}

